using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class EstimatesTraining : TrainingContentBase
{
    public EstimatesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Overview",
            Slug = "estimates-overview",
            Summary = "What estimates are, how they differ from quotes, their non-binding nature, and how to convert them into formal quotes.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers"]""",
            ContentJson = """{"body":"## Estimates Overview\n\nEstimates are lighter-weight pricing documents you provide to customers earlier in the conversation than a formal quote. They give customers a cost picture without the full ceremony of a binding quote. Estimates live inside the customer detail page on the Estimates tab — they are always tied to a specific customer.\n\n### Estimates vs Quotes\n\nEstimates and quotes serve different purposes in the sales pipeline:\n\n- **Estimate** — Starts from a single ballpark amount with a title and optional description, and can be itemized with line items afterward. No tax calculation, no shipping address, and no sales-order conversion of its own. Stored in the quotes table with type = Estimate.\n- **Quote** — A binding, fixed-price commitment with individual line items (part, quantity, unit price), a tax rate, and a formal lifecycle. Can be converted to a Sales Order. Stored in the quotes table with type = Quote.\n\nThe fast path is still simple: when a customer calls and asks 'how much would it cost to make 500 of these?', create an estimate with just a title and an amount in seconds. When you want to break that number down, reopen the estimate and add line items.\n\n### Line Items on an Estimate\n\nEstimates support line items, but they are managed on a **saved** estimate — not in the initial create dialog. The flow is header-first:\n\n1. Create the estimate with a title and an estimated amount (and optionally a description, valid-until date, and notes).\n2. Reopen it (click its row) — the edit dialog now shows a **Lines** section beneath the form.\n3. Use **Add Line** to itemize. Each line can be a **catalog part** (pick it from the part autocomplete — the description prefills) or a **lump-sum / unknown** line (leave the part empty and type a free-text description). Set a quantity and an amount (unit price) for each.\n\nAs you add, edit, or delete lines, the estimate's **Estimated Amount syncs to the sum of the line totals** — the header amount and the itemized lines stay in agreement. A line with no part shows 'Lump sum' in the Part column.\n\nLine editing is available only while the estimate is in **Draft** and has not been converted. Once it is Sent, Accepted, or converted to a quote, the lines become read-only.\n\n### The Estimate Lifecycle\n\nEvery estimate starts in **Draft** status and moves through a straightforward lifecycle:\n\n1. **Draft** — Just created, still being refined. You can edit the title, amount, description, notes, and line items freely.\n2. **Sent** — You've shared the estimate with the customer (via email, PDF, or verbally). The header fields stay editable; line items become read-only.\n3. **Accepted** — The customer agreed to move forward based on the estimate.\n4. **Declined** — The customer decided not to proceed.\n5. **Expired** — The estimate passed its Valid Until date without a decision.\n6. **Converted to Quote** — The estimate was converted into a formal quote. The estimate record is preserved with a link to the generated quote.\n\n### Converting to a Quote\n\nWhen a customer accepts an estimate and wants to move forward, you convert it to a formal quote. Click the forward arrow icon on the estimate row and confirm. This:\n\n- Creates a new Quote (type = Quote) in Draft status with an auto-generated quote number\n- Carries over the customer and the estimate's line items\n- Sets the estimate's status to Converted to Quote\n- Records the conversion timestamp\n- Links the new quote back to the source estimate via the source_estimate_id field\n\nFrom there you refine pricing, add the tax rate, and run the normal quote lifecycle on the Quotes page.\n\n### When to Use Estimates\n\n- When a customer asks for a rough cost before you've done detailed engineering\n- When you want to qualify a lead before investing time in a full quote\n- When you need a fast turnaround on pricing (a header-only estimate takes seconds to create)\n- When you want to show a customer a simple line breakdown without committing to a binding quote\n\n### Where to Find Estimates\n\nEstimates are accessed through the customer detail page. Navigate to Customers, select a customer, then click the Estimates tab. All estimates for that customer are listed in a sortable, filterable data table. You can create, edit (including line items), convert, and delete estimates directly from this tab.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates — Guided Tour",
            Slug = "estimates-walkthrough",
            Summary = "A guided tour of creating and managing estimates via the customer detail Estimates tab.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","walkthrough"]""",
            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Estimates","steps":[{"element":"app-data-table","popover":{"title":"Customer List","description":"Start by selecting a customer. Click any row to open the customer detail page where you can manage their estimates, quotes, orders, and more.","side":"top"}},{"element":"[data-testid='new-customer-btn']","popover":{"title":"Create Customer","description":"Before creating estimates, you need a customer. Click here to add one.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Customers","description":"Browse customers to access their estimates. Search by name, company, email, or phone, then click a customer row to open their detail page and navigate to the Estimates tab.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Creating and Itemizing an Estimate","description":"On a customer's Estimates tab, click 'New Estimate' and enter just a Title and an Estimated Amount to save the header. To break the number down, click the saved estimate's row to reopen it — a Lines section appears below the form. Use 'Add Line' to add a catalog part (pick it from the autocomplete; the description prefills) or a lump-sum line (leave the part empty and type a description), then set a quantity and amount. The Estimated Amount syncs to the sum of the lines. Line editing is available only while the estimate is in Draft and hasn't been converted.","side":"top"}},{"element":"app-data-table","popover":{"title":"Converting to a Quote","description":"When the customer wants to proceed, click the forward-arrow icon on the estimate row and confirm. This creates a Draft quote that carries over the customer and the estimate's line items, and marks the estimate Converted to Quote. You then refine pricing and add the tax rate on the Quotes page.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Field Reference",
            Slug = "estimates-field-reference",
            Summary = "Complete reference for every field, status, action, and validation rule in the Estimates feature.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","reference"]""",
            ContentJson = """{"title":"Estimates Field Reference","groups":[{"heading":"Estimate Form Fields","items":[{"label":"Title (required)","value":"Text input, max 300 characters. Identifies the estimate. Examples: 'CNC Bracket Prototype — 500 pcs', 'Tooling for Widget Housing'. Must not be empty."},{"label":"Description","value":"Textarea, optional, max 2000 characters. Longer explanation of what the estimate covers — assumptions, scope, exclusions."},{"label":"Estimated Amount (required)","value":"Currency input with $ prefix. The ballpark dollar figure. Must be zero or greater. Once you add line items to a saved estimate, this amount syncs to the sum of the line totals."},{"label":"Valid Until","value":"Datepicker, optional. Expiration date for the estimate. After this date the estimate is considered expired if the customer hasn't responded."},{"label":"Status (edit only)","value":"Dropdown, shown only when editing an existing estimate. Options: Draft, Sent, Accepted, Declined, Expired. Not shown on create (defaults to Draft). ConvertedToQuote is set automatically by the conversion action."},{"label":"Notes","value":"Textarea, optional, max 2000 characters. Internal notes — assumptions, material considerations, follow-up reminders."}]},{"heading":"Estimate Statuses","items":[{"label":"Draft (gray chip)","value":"Initial status. Estimate is being prepared. Fully editable."},{"label":"Sent (blue chip)","value":"Estimate has been shared with the customer. Still editable."},{"label":"Accepted (green chip)","value":"Customer agreed to proceed based on this ballpark figure."},{"label":"Declined (red chip)","value":"Customer decided not to proceed."},{"label":"Expired (yellow chip)","value":"Estimate passed its Valid Until date without a customer decision."},{"label":"Converted to Quote (purple chip)","value":"Estimate was converted into a formal quote. Set automatically by the Convert action. The generated quote ID is linked."}]},{"heading":"Line Items (saved Draft estimate)","items":[{"label":"Where","value":"The Lines section appears in the edit dialog of a SAVED estimate (reopen an estimate by clicking its row). It is not present in the create dialog — an estimate is created header-first, then itemized on reopen."},{"label":"When editable","value":"Add Line and the per-line Edit/Delete actions render only while the estimate is in Draft status and has not been converted. On Sent/Accepted/converted estimates the lines are read-only and a hint explains this."},{"label":"Add Line button","value":"Opens an inline add form below the lines table. Disabled while another line is already being edited."},{"label":"Catalog Part (optional)","value":"Entity-picker over the parts catalog (shown only when ADDING a line). Selecting a part prefills the Description when blank. Leave it empty to create a lump-sum / unknown line — the Part column then shows 'Lump sum'."},{"label":"Description (required)","value":"Text input. Required for each line. Free-text description of the line."},{"label":"Qty (required)","value":"Number input. Required, minimum 0.0001 (step 0.0001) — fractional quantities allowed."},{"label":"Amount (required)","value":"Currency input. Required, minimum 0. The per-unit amount for the line. Line total = Qty × Amount."},{"label":"Edit (pencil) / Delete (trash)","value":"Per-row actions. Edit reopens that row's description/qty/amount (the part is not changed). Delete removes the line after a confirmation dialog."},{"label":"Estimated Amount sync","value":"After any add/edit/delete, the estimate's header Estimated Amount is refreshed to the sum of the line totals and the list row updates."}]},{"heading":"Actions","items":[{"label":"New Estimate (primary button)","value":"Opens the create dialog. Fields: Title, Description, Estimated Amount, Valid Until, Notes. Saves in Draft status."},{"label":"Row click","value":"Opens the edit dialog pre-filled with the estimate's current values. The Status dropdown appears in edit mode."},{"label":"Convert to Quote (forward arrow icon)","value":"Creates a new formal Quote (type=Quote) in Draft status from this estimate. Sets the estimate's status to ConvertedToQuote. Carries over the customer and the estimate's line items. Refine pricing and add the tax rate on the Quotes page. Only available if the estimate hasn't already been converted (the icon is hidden once a generatedQuoteId exists)."},{"label":"Delete (trash icon)","value":"Soft-deletes the estimate after confirmation. Shows a danger confirmation dialog with the estimate title."},{"label":"Save (dialog button)","value":"Creates or updates the estimate. Disabled when form is invalid or save is in progress. Hover shows validation popover listing violations."},{"label":"Cancel (dialog button)","value":"Closes the dialog without saving."}]},{"heading":"Table Columns","items":[{"label":"Title","value":"Sortable. The estimate's title text."},{"label":"Amount","value":"Sortable (number type). Right-aligned. Displayed as formatted currency (e.g., $12,500.00)."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft (gray), Sent (blue), Accepted (green), Declined (red), Expired (yellow), ConvertedToQuote (purple)."},{"label":"Valid Until","value":"Sortable (date type). Displayed as MM/dd/yyyy. Blank if no expiration set."},{"label":"Created","value":"Sortable (date type). Displayed as MM/dd/yyyy. When the estimate was first created."},{"label":"Actions","value":"Not sortable. Contains Convert to Quote (forward arrow, hidden if already converted) and Delete (trash icon) buttons."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Max 300 characters. Cannot be empty."},{"label":"Estimated Amount","value":"Required. Must be a number >= 0. Currency mask applied."},{"label":"Description","value":"Optional. Max 2000 characters when provided."},{"label":"Notes","value":"Optional. Max 2000 characters when provided."},{"label":"Valid Until","value":"Optional. No past-date restriction — you can backdate if needed."},{"label":"Convert to Quote","value":"Only available if the estimate has not already been converted (no generatedQuoteId). Confirmation dialog required."},{"label":"Delete","value":"Confirmation dialog required (danger severity). Soft-delete — record preserved in database."}]},{"heading":"Navigation & Access","items":[{"label":"Location","value":"Customers page → select customer → Estimates tab. Estimates are always scoped to a single customer."},{"label":"Related features","value":"Quotes (formal, line-itemized commitments), Sales Orders (created from accepted quotes), Customer detail (parent page)."},{"label":"Data storage","value":"Estimates are stored in the quotes table with type=Estimate. They share the table with formal quotes but have different fields populated."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Knowledge Check",
            Slug = "estimates-quiz",
            Summary = "Test your knowledge of the Estimates feature: purpose, lifecycle, conversion to quotes, and field details.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"est1","text":"A customer calls and asks 'roughly how much would 500 aluminum brackets cost?' You don't have detailed engineering yet. What should you create in QB Engineer?","options":[{"id":"a","text":"A Quote with a single line item for 500 brackets"},{"id":"b","text":"A Sales Order with an estimated total"},{"id":"c","text":"An Estimate on the customer's Estimates tab with the ballpark amount","isCorrect":true},{"id":"d","text":"A Job on the Kanban board tagged as 'pricing'"}],"explanation":"Estimates are designed for exactly this scenario — providing a quick, non-binding ballpark figure before you've done detailed engineering. Create one on the customer's Estimates tab with a title and dollar amount."},{"id":"est2","text":"What is the key difference between an estimate and a quote in QB Engineer?","options":[{"id":"a","text":"Estimates require manager approval; quotes do not"},{"id":"b","text":"A quote is a binding commitment that carries a tax rate and can convert to a sales order; an estimate is lighter-weight, has no tax calculation, and can't convert to an order on its own — even though both can be line-itemized","isCorrect":true},{"id":"c","text":"Estimates have no line items at all; only quotes can be itemized"},{"id":"d","text":"Estimates are emailed automatically; quotes must be printed"}],"explanation":"Both documents can be itemized with line items. The real difference is commitment and scope: a quote is binding, carries a tax rate, and converts to a sales order; an estimate is lighter-weight, has no tax calculation, and converts to a quote (not directly to an order). The 'estimates have no line items' idea is outdated — estimates support catalog-part and lump-sum lines."},{"id":"est3","text":"Where do you find and manage estimates in QB Engineer?","options":[{"id":"a","text":"On a dedicated Estimates page in the main navigation"},{"id":"b","text":"On the customer detail page, under the Estimates tab","isCorrect":true},{"id":"c","text":"In the Quotes module, filtered by type"},{"id":"d","text":"On the Dashboard under the Sales widget"}],"explanation":"Estimates are accessed through the customer detail page. Navigate to Customers, select a customer, then click the Estimates tab. All estimates for that customer are listed there."},{"id":"est4","text":"You created an estimate last week and the customer just said they want to proceed. What is the next step?","options":[{"id":"a","text":"Change the estimate's status to Accepted, then create a Sales Order manually"},{"id":"b","text":"Delete the estimate and create a Quote from scratch"},{"id":"c","text":"Click the Convert to Quote icon on the estimate row — it creates a new formal quote linked to the estimate","isCorrect":true},{"id":"d","text":"There's no conversion — you re-key the estimate as a brand-new quote by hand"}],"explanation":"Click the forward arrow icon on the estimate row to convert it. This creates a new Quote (type=Quote) in Draft status, carries over the customer and line items, sets the estimate to ConvertedToQuote, and links them together. You then refine pricing on the new quote — you don't re-key it by hand."},{"id":"est5","text":"What happens to an estimate after it is converted to a quote?","options":[{"id":"a","text":"The estimate is deleted and replaced by the quote"},{"id":"b","text":"The estimate's status changes to ConvertedToQuote, and it links to the new quote. The estimate record is preserved.","isCorrect":true},{"id":"c","text":"The estimate becomes editable again so you can update the amount"},{"id":"d","text":"The estimate is archived and hidden from the Estimates tab"}],"explanation":"The estimate is preserved with its status set to ConvertedToQuote and a conversion timestamp. It maintains a link to the generated quote via the generatedQuoteId field. You can still see it in the Estimates tab."},{"id":"est6","text":"Which fields are required when creating a new estimate?","options":[{"id":"a","text":"Title, Description, Estimated Amount, and Valid Until date"},{"id":"b","text":"Title and Estimated Amount only — line items are added afterward on the saved estimate","isCorrect":true},{"id":"c","text":"Title, Estimated Amount, and at least one line item"},{"id":"d","text":"Only the Estimated Amount — everything else is optional"}],"explanation":"The create dialog requires only two fields: Title (max 300 characters) and Estimated Amount (must be >= 0). Description, Valid Until, and Notes are optional. Line items are not part of the create step — an estimate is created header-first, then itemized in the edit dialog after it's saved (where the Estimated Amount then syncs to the line totals)."},{"id":"est7","text":"An estimate shows a yellow 'Expired' status chip. What does this mean?","options":[{"id":"a","text":"The estimate was rejected by the customer"},{"id":"b","text":"The estimate passed its Valid Until date without a customer decision","isCorrect":true},{"id":"c","text":"The estimate has been converted to a quote"},{"id":"d","text":"The estimate was created more than 30 days ago"}],"explanation":"Expired (yellow chip) means the estimate passed its Valid Until date without the customer accepting or declining. You can still edit the estimate and extend the date if needed."},{"id":"est8","text":"A new quote was created from an estimate conversion. What state does the new quote start in?","options":[{"id":"a","text":"Draft status, carrying over the estimate's customer and line items — you then refine pricing and add the tax rate","isCorrect":true},{"id":"b","text":"Sent status, already shared with the customer"},{"id":"c","text":"Accepted status since the customer already agreed to the estimate"},{"id":"d","text":"Draft status with no line items — everything must be re-entered from scratch"}],"explanation":"The converted quote starts in Draft status and carries over the estimate's customer and its line items. From there you refine the pricing, add the tax rate, and run the normal quote lifecycle. You don't re-enter the lines from scratch — that's the whole point of converting rather than starting a new quote."},{"id":"est9","text":"You want to delete an estimate that was entered by mistake. What happens?","options":[{"id":"a","text":"The estimate is permanently removed from the database"},{"id":"b","text":"The estimate is soft-deleted — the record is preserved in the database but hidden from the UI. A confirmation dialog appears first.","isCorrect":true},{"id":"c","text":"The estimate moves to a Trash folder where it can be restored within 30 days"},{"id":"d","text":"You cannot delete estimates — you can only change their status to Declined"}],"explanation":"Deleting an estimate triggers a danger confirmation dialog. On confirmation, the record is soft-deleted (DeletedAt timestamp set) — it's preserved in the database for audit purposes but no longer visible in the Estimates tab."},{"id":"est10","text":"Can you convert the same estimate to a quote more than once?","options":[{"id":"a","text":"Yes — each conversion creates an additional quote linked to the same estimate"},{"id":"b","text":"No — once an estimate has been converted, the Convert to Quote button is hidden and the API prevents duplicate conversion","isCorrect":true},{"id":"c","text":"Yes, but only if the first generated quote was deleted"},{"id":"d","text":"No — you must create a new estimate to generate another quote"}],"explanation":"An estimate can only be converted once. The Convert to Quote icon is hidden for estimates that already have a generatedQuoteId. The API also validates this — if the estimate already has a generated quote, it throws an error: 'Estimate has already been converted to a quote.'"}]}"""
        });

        Log.Information("Seeded Estimates training modules");
    }
}
